function ConnectionsScreen({ setScreen }) {
  const [stage, setStage] = useState("connect");
  const [selectedService, setSelectedService] = useState(null);
  const [pickedClient, setPickedClient] = useState(null);
  const [manualForm, setManualForm] = useState({ client: "", invoice: "", amount: "", dueDate: "", terms: "Net 30", notes: "" });
  const [manualSubmitted, setManualSubmitted] = useState(false);

  const handleServiceClick = (svc) => {
    if (svc.id === "manual") { setSelectedService(svc); setStage("manual"); return; }
    setSelectedService(svc);
    setStage("connecting");
    setTimeout(() => setStage("select"), 1600);
  };

  const handleClientPick = (c) => {
    setPickedClient(c);
    setStage("analyzing");
    setTimeout(() => setScreen("dashboard"), 2000);
  };

  return (
    <div style={{ padding: "36px 48px", minHeight: 520, fontFamily: C.sans }}>
      <style>{`
        @keyframes fadeUp{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
        @keyframes bar{from{width:0%}to{width:100%}}
        button:focus-visible{outline:2px solid #2B6CB0;outline-offset:2px}
      `}</style>

      {stage === "connect" && (
        <>
          <button onClick={() => setScreen("dashboard")} style={{ display: "flex", alignItems: "center", gap: 6, padding: "8px 12px", fontSize: 14, fontWeight: 600, color: C.blue, background: "transparent", border: "none", cursor: "pointer", marginBottom: 20 }} onMouseEnter={(e) => e.currentTarget.style.textDecoration = "underline"} onMouseLeave={(e) => e.currentTarget.style.textDecoration = "none"}>
            <span style={{ fontSize: 16 }}>←</span> Back to Recovery
          </button>

          <div style={{ maxWidth: 860, margin: "0 auto", textAlign: "center" }}>
            <div style={{ marginBottom: 40 }}>
              <div style={{ fontSize: 12, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.12em", marginBottom: 4 }}>Clyintel</div>
              <div style={{ fontSize: 28, fontWeight: 700, color: C.navy, marginBottom: 8 }}>Add Client</div>
              <div style={{ fontSize: 15, color: C.textMid }}>Connect your invoice source, import a file, or enter an invoice manually.</div>
            </div>

            {/* Integrations */}
            <div style={{ marginBottom: 36 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: 16 }}>Connect an Integration</div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 16 }}>
                {invoiceServices.filter(s => s.id !== "gdrive" && s.id !== "manual").map(svc => (
                  <div key={svc.id} onClick={() => handleServiceClick(svc)} style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 12, padding: "28px 20px", cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center", gap: 14, textAlign: "center", transition: "border-color 0.15s" }} onMouseEnter={(e) => { e.currentTarget.style.borderColor = C.blue; e.currentTarget.style.boxShadow = `0 0 0 3px ${C.blueBg}`; }} onMouseLeave={(e) => { e.currentTarget.style.borderColor = C.border; e.currentTarget.style.boxShadow = "none"; }}>
                    <div style={{ width: 56, height: 56, borderRadius: 14, background: svc.color, display: "flex", alignItems: "center", justifyContent: "center" }}>
                      <span style={{ fontSize: 16, fontWeight: 700, color: "#fff" }}>{svc.initial}</span>
                    </div>
                    <div>
                      <div style={{ fontSize: 15, fontWeight: 600, color: C.text }}>{svc.name}</div>
                      <div style={{ fontSize: 12, color: C.textDim, marginTop: 4 }}>{svc.subtitle}</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Divider */}
            <div style={{ display: "flex", alignItems: "center", gap: 16, marginBottom: 36 }}>
              <div style={{ flex: 1, height: 1, background: C.border }} />
              <div style={{ fontSize: 12, color: C.textDim, fontWeight: 500 }}>or</div>
              <div style={{ flex: 1, height: 1, background: C.border }} />
            </div>

            {/* File Import + Manual — side by side */}
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
              {[
                invoiceServices.find(s => s.id === "gdrive"),
                invoiceServices.find(s => s.id === "manual"),
              ].map(svc => (
                <div key={svc.id} onClick={() => handleServiceClick(svc)} style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 12, padding: "28px 28px", cursor: "pointer", display: "flex", alignItems: "center", gap: 18, textAlign: "left", transition: "border-color 0.15s" }} onMouseEnter={(e) => { e.currentTarget.style.borderColor = C.blue; e.currentTarget.style.boxShadow = `0 0 0 3px ${C.blueBg}`; }} onMouseLeave={(e) => { e.currentTarget.style.borderColor = C.border; e.currentTarget.style.boxShadow = "none"; }}>
                  <div style={{ width: 56, height: 56, borderRadius: 14, background: svc.color, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                    <span style={{ fontSize: 16, fontWeight: 700, color: "#fff" }}>{svc.initial}</span>
                  </div>
                  <div>
                    <div style={{ fontSize: 15, fontWeight: 600, color: C.text }}>{svc.name}</div>
                    <div style={{ fontSize: 13, color: C.textDim, marginTop: 4 }}>{svc.subtitle}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </>
      )}

      {stage === "connecting" && selectedService && (
        <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: 360 }}>
          <div style={{ width: 52, height: 52, borderRadius: 14, background: selectedService.color, display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 18 }}>
            <span style={{ fontSize: 17, fontWeight: 700, color: "#fff" }}>{selectedService.initial}</span>
          </div>
          <div style={{ fontSize: 15, fontWeight: 500, color: C.text, marginBottom: 6 }}>Connecting to {selectedService.name}...</div>
          <div style={{ fontSize: 13, color: C.textMid, marginBottom: 24 }}>Syncing invoice history</div>
          <div style={{ width: 280, height: 4, background: C.border, borderRadius: 2, overflow: "hidden" }}>
            <div style={{ height: "100%", background: C.blue, borderRadius: 2, animation: "bar 1.6s ease forwards" }} />
          </div>
        </div>
      )}

      {stage === "select" && selectedService && (
        <>
          <div style={{ marginBottom: 24 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
              <div style={{ width: 20, height: 20, borderRadius: 5, background: selectedService.color, display: "flex", alignItems: "center", justifyContent: "center" }}>
                <span style={{ fontSize: 8, fontWeight: 700, color: "#fff" }}>{selectedService.initial}</span>
              </div>
              <span style={{ fontSize: 12, color: C.green, fontWeight: 500 }}>✓ {selectedService.name} connected</span>
            </div>
            <div style={{ fontSize: 22, fontWeight: 600, color: C.text, marginBottom: 6 }}>Select a client</div>
            <div style={{ fontSize: 13, color: C.textMid }}>Choose a client to analyze and score.</div>
          </div>
          <div style={{ border: `1px solid ${C.border}`, borderRadius: 10, overflow: "hidden", maxWidth: 580 }}>
            <div style={{ display: "grid", gridTemplateColumns: "2fr 90px 110px", padding: "9px 16px", background: C.surface, borderBottom: `1px solid ${C.border}` }}>
              {["Client", "Invoices", "Balance"].map(h => (
                <span key={h} style={{ fontSize: 11, fontWeight: 600, color: C.textMid, textTransform: "uppercase", letterSpacing: "0.06em" }}>{h}</span>
              ))}
            </div>
            {importedClients.map((c, i) => (
              <div key={c.name} onClick={() => handleClientPick(c)} style={{ display: "grid", gridTemplateColumns: "2fr 90px 110px", alignItems: "center", padding: "13px 16px", borderBottom: i < importedClients.length - 1 ? `1px solid ${C.border}` : "none", cursor: "pointer" }} onMouseEnter={(e) => e.currentTarget.style.background = C.blueBg} onMouseLeave={(e) => e.currentTarget.style.background = "transparent"}>
                <div style={{ fontSize: 13, fontWeight: 500, color: C.text }}>{c.name}</div>
                <div style={{ fontSize: 13, color: C.textMid, fontFamily: C.mono }}>{c.invoices}</div>
                <div style={{ fontSize: 13, fontWeight: 500, color: c.balance > 0 ? C.text : C.textDim, fontFamily: C.mono }}>{c.balance > 0 ? `$${c.balance.toLocaleString()}` : "—"}</div>
              </div>
            ))}
          </div>
        </>
      )}

      {stage === "analyzing" && (
        <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: 360 }}>
          <div style={{ fontSize: 15, fontWeight: 500, color: C.text, marginBottom: 6 }}>Analyzing {pickedClient?.name}...</div>
          <div style={{ fontSize: 13, color: C.textMid, marginBottom: 24 }}>Scoring invoice history and calculating risk</div>
          <div style={{ width: 280, height: 4, background: C.border, borderRadius: 2, overflow: "hidden" }}>
            <div style={{ height: "100%", background: C.blue, borderRadius: 2, animation: "bar 2s ease forwards" }} />
          </div>
        </div>
      )}

      {stage === "manual" && !manualSubmitted && (
        <>
          <button onClick={() => setStage("connect")} style={{ display: "flex", alignItems: "center", gap: 6, padding: "8px 12px", fontSize: 14, fontWeight: 600, color: C.blue, background: "transparent", border: "none", cursor: "pointer", marginBottom: 12 }} onMouseEnter={(e) => e.currentTarget.style.textDecoration = "underline"} onMouseLeave={(e) => e.currentTarget.style.textDecoration = "none"}>
            <span style={{ fontSize: 16 }}>←</span> Back
          </button>
          <div style={{ marginBottom: 24 }}>
            <div style={{ fontSize: 22, fontWeight: 600, color: C.text, marginBottom: 6 }}>Create Invoice Manually</div>
            <div style={{ fontSize: 13, color: C.textMid }}>Enter invoice details to add a client and invoice to Clyintel.</div>
          </div>
          <div style={{ maxWidth: 520, background: C.card, border: `1px solid ${C.border}`, borderRadius: 12, padding: "28px 32px" }}>
            {MANUAL_FIELDS.map(field => (
              <div key={field.id} style={{ marginBottom: 20 }}>
                <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: C.text, marginBottom: 6 }}>{field.label}</label>
                {field.type === "select" ? (
                  <select value={manualForm[field.id]} onChange={(e) => setManualForm({ ...manualForm, [field.id]: e.target.value })} style={{ width: "100%", padding: "9px 12px", fontSize: 13, border: `1px solid ${C.border}`, borderRadius: 6, background: "#FFFFFF", color: C.text }}>
                    {field.options.map(o => <option key={o}>{o}</option>)}
                  </select>
                ) : field.type === "textarea" ? (
                  <textarea value={manualForm[field.id]} onChange={(e) => setManualForm({ ...manualForm, [field.id]: e.target.value })} placeholder={field.placeholder} rows={3} style={{ width: "100%", padding: "9px 12px", fontSize: 13, border: `1px solid ${C.border}`, borderRadius: 6, background: "#FFFFFF", color: C.text, fontFamily: "inherit", resize: "vertical", boxSizing: "border-box" }} />
                ) : (
                  <input type={field.type} value={manualForm[field.id]} onChange={(e) => setManualForm({ ...manualForm, [field.id]: e.target.value })} placeholder={field.placeholder} style={{ width: "100%", padding: "9px 12px", fontSize: 13, border: `1px solid ${C.border}`, borderRadius: 6, background: "#FFFFFF", color: C.text, boxSizing: "border-box" }} />
                )}
              </div>
            ))}
            <div style={{ display: "flex", justifyContent: "flex-end", gap: 10, paddingTop: 8, borderTop: `1px solid ${C.border}` }}>
              <button onClick={() => setStage("connect")} style={{ padding: "9px 18px", fontSize: 13, fontWeight: 600, color: C.textMid, background: "#FFFFFF", border: `1px solid ${C.border}`, borderRadius: 6, cursor: "pointer" }}>Cancel</button>
              <button onClick={() => { setManualSubmitted(true); setTimeout(() => setScreen("dashboard"), 1800); }} style={{ padding: "9px 18px", fontSize: 13, fontWeight: 600, color: "#FFFFFF", background: C.blue, border: "none", borderRadius: 6, cursor: "pointer" }}>Save Invoice</button>
            </div>
          </div>
        </>
      )}

      {stage === "manual" && manualSubmitted && (
        <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: 360 }}>
          <div style={{ fontSize: 32, marginBottom: 16 }}>✓</div>
          <div style={{ fontSize: 15, fontWeight: 500, color: C.text, marginBottom: 6 }}>Invoice saved</div>
          <div style={{ fontSize: 13, color: C.textMid }}>Returning to dashboard...</div>
        </div>
      )}
    </div>
  );
}

function ExchangeDrawer({ invoiceId, onClose }) {
  const exchanges = invoiceExchanges[invoiceId] || [];
  const channelIcons = { "Voice": "📞", "Email": "📧", "Text": "💬" };
  const channelColors = { "Voice": C.blue, "Email": C.amber, "Text": C.green };

  return (
    <>
      <div onClick={onClose} style={{ position: "fixed", top: 0, left: 0, right: 0, bottom: 0, background: "rgba(0,0,0,0.3)", zIndex: 999 }} />
      <div style={{ position: "fixed", top: 0, right: 0, bottom: 0, width: 500, background: "#FFFFFF", boxShadow: "-4px 0 24px rgba(0,0,0,0.15)", zIndex: 1000, display: "flex", flexDirection: "column", fontFamily: C.sans }}>
        <style>{`@keyframes slideInRight{from{transform:translateX(100%)}to{transform:translateX(0)}}`}</style>
        <div style={{ animation: "slideInRight 0.3s ease-out", display: "flex", flexDirection: "column", height: "100%" }}>
          <div style={{ padding: "24px 28px", borderBottom: `1px solid ${C.border}`, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div>
              <div style={{ fontSize: 20, fontWeight: 600, color: C.text, marginBottom: 4 }}>Recovery Agent Exchanges</div>
              <div style={{ fontSize: 14, color: C.textMid, fontFamily: C.mono }}>Invoice {invoiceId}</div>
            </div>
            <button onClick={onClose} style={{ padding: "8px 12px", fontSize: 18, color: C.textMid, background: "transparent", border: "none", cursor: "pointer" }}>✕</button>
          </div>
          <div style={{ flex: 1, overflowY: "auto", padding: "24px 28px" }}>
            {exchanges.length > 0 ? (
              <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
                {exchanges.map((ex, idx) => (
                  <div key={idx} style={{ borderLeft: `3px solid ${channelColors[ex.channel] || C.textMid}`, paddingLeft: 16, paddingBottom: 16, borderBottom: idx < exchanges.length - 1 ? `1px solid ${C.border}` : "none" }}>
                    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 8 }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                        <span style={{ fontSize: 16 }}>{channelIcons[ex.channel] || "📋"}</span>
                        <span style={{ fontSize: 11, fontWeight: 600, color: "#FFFFFF", background: channelColors[ex.channel] || C.textMid, padding: "2px 8px", borderRadius: 4, textTransform: "uppercase", letterSpacing: "0.5px" }}>{ex.channel}</span>
                        <span style={{ fontSize: 13, color: C.blue, fontFamily: C.mono, fontWeight: 500 }}>{ex.contact}</span>
                      </div>
                      <span style={{ fontSize: 13, color: C.textMid, fontFamily: C.mono }}>{ex.timestamp}</span>
                    </div>
                    <div style={{ fontSize: 13, color: C.textMid, marginBottom: 4 }}><span style={{ color: C.text, fontWeight: 500 }}>From:</span> {ex.from}</div>
                    <div style={{ fontSize: 13, color: C.textMid, marginBottom: 10 }}><span style={{ color: C.text, fontWeight: 500 }}>To:</span> {ex.to}</div>
                    <div style={{ fontSize: 14, color: C.text, marginBottom: 8, lineHeight: 1.5 }}>
                      <span style={{ fontWeight: 600, color: C.textMid }}>{ex.channel === "Email" ? "Body" : ex.channel === "Text" ? "Message" : "Summary"}:</span> {ex.message}
                    </div>
                    {ex.outcome && <div style={{ fontSize: 14, color: C.text, fontWeight: 600, marginTop: 10 }}><span style={{ color: C.amber }}>Outcome:</span> {ex.outcome}</div>}
                  </div>
                ))}
              </div>
            ) : (
              <div style={{ textAlign: "center", padding: "40px 20px", color: C.textMid, fontSize: 14 }}>No exchanges recorded for this invoice yet.</div>
            )}
          </div>
        </div>
      </div>
    </>
  );
}

function ClientListScreen({ setScreen, onSelectClient }) {
  const totalOutstanding = clients.reduce((sum, c) => sum + c.balance, 0);
  const getRecoveryYTD = (id) => ({ 4: 15800, 1: 3200, 2: 8400, 3: 12400, 5: 2800 }[id] || 0);
  const totalRecovery = clients.reduce((sum, c) => sum + getRecoveryYTD(c.id), 0);
  const lowRisk = clients.filter(c => c.score >= 80).length;
  const mediumRisk = clients.filter(c => c.score >= 60 && c.score < 80).length;
  const highRisk = clients.filter(c => c.score < 60).length;
  const scores = clients.map(c => c.score);

  return (
    <div style={{ padding: "28px 36px", minHeight: 520, fontFamily: C.sans }}>
      <button onClick={() => setScreen("dashboard")} style={{ display: "flex", alignItems: "center", gap: 6, padding: "8px 12px", fontSize: 14, fontWeight: 600, color: C.blue, background: "transparent", border: "none", cursor: "pointer", marginBottom: 12 }} onMouseEnter={(e) => e.currentTarget.style.textDecoration = "underline"} onMouseLeave={(e) => e.currentTarget.style.textDecoration = "none"}>
        <span style={{ fontSize: 16 }}>←</span> Back to Recovery
      </button>
      <div style={{ fontSize: 12, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.12em", marginBottom: 4 }}>Clyintel</div>
      <div style={{ fontSize: 28, fontWeight: 600, color: C.navy, marginBottom: 24 }}>Portfolio Dashboard</div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 16, marginBottom: 24 }}>
        <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 10, padding: 20 }}>
          <div style={{ fontSize: 12, fontWeight: 600, color: C.navy, marginBottom: 12, textTransform: "uppercase" }}>Risk Distribution</div>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {[{ label: "Low Risk", count: lowRisk, color: C.green }, { label: "Medium Risk", count: mediumRisk, color: C.amber }, { label: "High Risk", count: highRisk, color: C.red }].map(item => (
              <div key={item.label} style={{ display: "flex", justifyContent: "space-between", fontSize: 13 }}>
                <span style={{ color: item.color }}>{item.label}</span>
                <span style={{ fontWeight: 600, color: item.color }}>{item.count}</span>
              </div>
            ))}
          </div>
        </div>
        <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 10, padding: 20 }}>
          <div style={{ fontSize: 12, fontWeight: 600, color: C.navy, marginBottom: 12, textTransform: "uppercase" }}>Financial Overview</div>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
            <span style={{ fontSize: 11, color: C.textMid }}>Outstanding</span>
            <span style={{ fontSize: 16, fontWeight: 600, color: C.red, fontFamily: C.mono }}>${(totalOutstanding / 1000).toFixed(0)}K</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between" }}>
            <span style={{ fontSize: 11, color: C.textMid }}>Recovery YTD</span>
            <span style={{ fontSize: 16, fontWeight: 600, color: C.green, fontFamily: C.mono }}>${(totalRecovery / 1000).toFixed(0)}K</span>
          </div>
        </div>
        <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 10, padding: 20 }}>
          <div style={{ fontSize: 12, fontWeight: 600, color: C.navy, marginBottom: 12, textTransform: "uppercase" }}>Portfolio Stats</div>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
            <span style={{ fontSize: 11, color: C.textMid }}>Total Clients</span>
            <span style={{ fontSize: 16, fontWeight: 600, color: C.blue, fontFamily: C.mono }}>{clients.length}</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between" }}>
            <span style={{ fontSize: 11, color: C.textMid }}>Score Range</span>
            <span style={{ fontSize: 16, fontWeight: 600, color: C.text, fontFamily: C.mono }}>{Math.max(...scores)}–{Math.min(...scores)}</span>
          </div>
        </div>
      </div>

      <div style={{ border: `1px solid ${C.border}`, borderRadius: 10, overflow: "hidden" }}>
        <div style={{ display: "grid", gridTemplateColumns: "200px 140px 140px 120px 100px 140px 140px", gap: 16, padding: "12px 16px", background: C.surface, borderBottom: `1px solid ${C.border}`, fontSize: 11, fontWeight: 600, color: C.navy, textTransform: "uppercase" }}>
          <div>Client Name</div><div>Industry</div><div>Score</div><div>Status</div><div>Invoices</div><div>Outstanding</div><div>Recovery YTD</div>
        </div>
        {clients.map((client, i) => {
          const scoreColor = client.score >= 80 ? C.green : client.score >= 60 ? C.amber : C.red;
          const recoveryYTD = getRecoveryYTD(client.id);
          const prevScore = client.score >= 80 ? client.score - 3 : client.score + 2;
          const scoreDelta = client.score - prevScore;
          let statusColor = C.red, statusLabel = "Past Due";
          if (client.status === "recovered") { statusColor = C.green; statusLabel = "Paid"; }
          else if (client.status === "current") { statusColor = C.green; statusLabel = "Current"; }
          else if (client.status === "due") { statusColor = C.amber; statusLabel = "Due Soon"; }
          const invoices = clientInvoices[client.id];
          const currentInvoices = invoices ? (invoices.outstanding?.length || 0) + (invoices.upcoming?.length || 0) : 0;

          return (
            <div key={client.id} onClick={() => { onSelectClient(client); setScreen("detail"); }} style={{ display: "grid", gridTemplateColumns: "200px 140px 140px 120px 100px 140px 140px", gap: 16, padding: "14px 16px", borderBottom: i < clients.length - 1 ? `1px solid ${C.border}` : "none", cursor: "pointer", transition: "background 0.15s" }} onMouseEnter={(e) => e.currentTarget.style.background = C.blueBg} onMouseLeave={(e) => e.currentTarget.style.background = "transparent"}>
              <div style={{ fontSize: 14, fontWeight: 600, color: C.navy }}>{client.name}</div>
              <div style={{ fontSize: 13, color: C.textMid }}>{client.industry}</div>
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <span style={{ fontSize: 15, fontWeight: 600, color: scoreColor, fontFamily: C.mono }}>{client.score}</span>
                <span style={{ fontSize: 12, color: scoreDelta > 0 ? C.green : C.red, fontFamily: C.mono }}>{scoreDelta > 0 ? "▲" : "▼"} {Math.abs(scoreDelta)}</span>
              </div>
              <div style={{ fontSize: 13, fontWeight: 500, color: statusColor }}>{statusLabel}</div>
              <div style={{ fontSize: 14, fontFamily: C.mono }}>{currentInvoices}/{client.invoices}</div>
              <div style={{ fontSize: 15, fontWeight: 400, color: client.balance > 0 ? C.red : C.text, fontFamily: C.mono }}>${client.balance.toLocaleString()}</div>
              <div style={{ fontSize: 15, fontWeight: 400, color: recoveryYTD > 0 ? C.green : C.textMid, fontFamily: C.mono }}>{recoveryYTD > 0 ? `$${recoveryYTD.toLocaleString()}` : "—"}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function RecoveryRecModal({ card, onUpdate, onClose }) {
  const [editAmount, setEditAmount] = useState(card.editAmount);
  return (
    <div onClick={onClose} style={{ position: "fixed", top: 0, left: 0, right: 0, bottom: 0, background: "rgba(0,0,0,0.45)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000, fontFamily: C.sans }}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: "#FFFFFF", borderRadius: 12, width: 600, maxHeight: "85vh", overflow: "auto", boxShadow: "0 20px 40px rgba(0,0,0,0.18)" }}>
        {/* Modal header */}
        <div style={{ padding: "22px 28px", borderBottom: `1px solid ${C.border}`, display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
          <div>
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
              <span style={{ fontSize: 10, fontWeight: 700, color: C.amber, letterSpacing: "0.08em", textTransform: "uppercase" }}>Agent Recovery Recommendation</span>
              {card.status === "approved" && <span style={{ fontSize: 11, fontWeight: 700, color: C.green, background: C.greenBg, padding: "2px 8px", borderRadius: 5 }}>✓ Approved</span>}
              {card.status === "dismissed" && <span style={{ fontSize: 11, fontWeight: 600, color: C.textDim, background: C.surface, padding: "2px 8px", borderRadius: 5 }}>Dismissed</span>}
            </div>
            <div style={{ fontSize: 18, fontWeight: 700, color: C.text }}>{card.client}</div>
            <div style={{ fontSize: 12, color: C.textDim, marginTop: 2 }}>Client Score: <span style={{ color: C.red, fontWeight: 700 }}>{card.score}</span></div>
            <div style={{ fontSize: 15, fontWeight: 600, fontFamily: C.mono, color: C.text, marginTop: 4 }}>{card.id}</div>
          </div>
          <button onClick={onClose} style={{ padding: "6px 10px", fontSize: 18, color: C.textMid, background: "transparent", border: "none", cursor: "pointer" }}>✕</button>
        </div>

        {/* Invoice details strip */}
        <div style={{ display: "flex", gap: 0, borderBottom: `1px solid ${C.border}`, background: C.surface }}>
          {[
            { label: "Amount", value: `$${card.invoiceAmount.toLocaleString()}`, mono: true, color: C.text },
            { label: "Days Overdue", value: `${card.daysOverdue}d`, mono: true, color: C.red },
            { label: "Full Loss Risk", value: card.riskOfFullLoss, mono: true, color: C.red },
            { label: "Last Contact", value: card.lastContact, mono: false, color: C.textMid },
          ].map((item, i, arr) => (
            <div key={item.label} style={{ flex: 1, padding: "12px 16px", borderRight: i < arr.length - 1 ? `1px solid ${C.border}` : "none" }}>
              <div style={{ fontSize: 10, fontWeight: 600, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 4 }}>{item.label}</div>
              <div style={{ fontSize: 13, fontWeight: 400, color: item.color, fontFamily: item.mono ? C.mono : C.sans }}>{item.value}</div>
            </div>
          ))}
        </div>

        {/* AI rationale */}
        <div style={{ padding: "20px 28px", borderBottom: `1px solid ${C.border}` }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: C.amber, textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: 8 }}>AI Rationale</div>
          <div style={{ fontSize: 13, color: C.textMid, lineHeight: 1.7 }}>{card.rationale}</div>
          <div style={{ marginTop: 12, padding: "10px 14px", background: C.surface, borderRadius: 7, border: `1px solid ${C.border}`, fontSize: 12, color: C.textDim }}>
            <span style={{ fontWeight: 600, color: C.text }}>If no action: </span>{card.alternativeOutcome}
          </div>
        </div>

        {/* Negotiate Amount panel */}
        <div style={{ padding: "20px 28px" }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: 14 }}>Negotiate Amount</div>
          <div style={{ display: "flex", gap: 20, alignItems: "flex-start", marginBottom: 20 }}>
            {/* AI floor */}
            <div style={{ flex: 1, background: C.amberBg, border: `1px solid ${C.amber}33`, borderRadius: 8, padding: "14px 16px" }}>
              <div style={{ fontSize: 11, color: C.amber, fontWeight: 600, marginBottom: 4 }}>AI Suggested Floor</div>
              <div style={{ fontSize: 24, fontWeight: 700, color: C.amber, fontFamily: C.mono }}>${card.suggestedAmount.toLocaleString()}</div>
              <div style={{ fontSize: 11, color: C.textDim, marginTop: 4 }}>{Math.round(card.suggestedAmount / card.invoiceAmount * 100)}% of original · lowest acceptable</div>
            </div>
            {/* Editable amount */}
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 11, fontWeight: 600, color: C.text, display: "block", marginBottom: 6 }}>
                Your floor amount <span style={{ color: C.textDim, fontWeight: 400 }}>(agent won't go below this)</span>
              </label>
              <div style={{ display: "flex", alignItems: "center", border: `1px solid ${C.border}`, borderRadius: 6, overflow: "hidden", background: "#FFFFFF", marginBottom: 6 }}>
                <span style={{ padding: "10px 12px", fontSize: 14, color: C.textMid, background: C.surface, borderRight: `1px solid ${C.border}` }}>$</span>
                <input
                  type="number"
                  value={editAmount}
                  onChange={(e) => setEditAmount(Number(e.target.value))}
                  style={{ flex: 1, padding: "10px 12px", fontSize: 14, fontFamily: C.mono, border: "none", outline: "none", color: C.text }}
                />
              </div>
              <div style={{ fontSize: 11, color: C.textDim }}>
                {editAmount > 0 && `${Math.round(editAmount / card.invoiceAmount * 100)}% of original · $${(card.invoiceAmount - editAmount).toLocaleString()} concession`}
              </div>
            </div>
          </div>

          {/* Action buttons */}
          <div style={{ display: "flex", justifyContent: "flex-end", gap: 10, paddingTop: 16, borderTop: `1px solid ${C.border}` }}>
            <button onClick={() => { onUpdate(card.id, { status: "dismissed", editAmount }); onClose(); }} style={{ padding: "9px 20px", fontSize: 13, fontWeight: 600, color: C.textMid, background: "#FFFFFF", border: `1px solid ${C.border}`, borderRadius: 6, cursor: "pointer" }}>Dismiss</button>
            <button onClick={() => { onUpdate(card.id, { status: "approved", editAmount }); onClose(); }} style={{ padding: "9px 20px", fontSize: 13, fontWeight: 700, color: "#FFFFFF", background: C.green, border: "none", borderRadius: 6, cursor: "pointer" }} onMouseEnter={(e) => e.currentTarget.style.opacity = "0.88"} onMouseLeave={(e) => e.currentTarget.style.opacity = "1"}>Authorize Agent</button>
          </div>
        </div>
      </div>
    </div>
  );
}

function NegotiationActions({ cards, onUpdate, activeModal, setActiveModal }) {
  const activeCard = cards.find(c => c.id === activeModal);
  const pendingCount = cards.filter(c => c.status === "pending").length;

  return (
    <div style={{ marginBottom: 28 }}>
      {/* Section header — just the title */}
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
        <div style={{ width: 3, height: 16, background: C.navy, borderRadius: 2 }} />
        <div style={{ fontSize: 13, fontWeight: 600, color: C.text }}>Recovery Recommendations</div>
      </div>

      {/* Slim cards — no border */}
      <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
        {cards.map(card => (
          <div key={card.id} style={{ display: "flex", alignItems: "center", gap: 16, padding: "12px 18px", borderRadius: 8, background: card.status === "approved" ? C.greenBg : card.status === "dismissed" ? C.surface : C.amberBg }}>
            {/* Left: client name + score */}
            <div style={{ width: 160 }}>
              <div style={{ fontSize: 13, fontWeight: 700, color: C.text }}>{card.client}</div>
              <div style={{ fontSize: 11, color: C.textDim, marginTop: 1 }}>Score <span style={{ color: C.red, fontWeight: 700 }}>{card.score}</span></div>
            </div>
            {/* Invoice # column */}
            <div style={{ width: 90 }}>
              <div style={{ fontSize: 10, color: C.textDim, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.07em" }}>Invoice #</div>
              <div style={{ fontSize: 13, fontFamily: C.mono, fontWeight: 400, color: C.text, marginTop: 2 }}>{card.id}</div>
            </div>
            {/* Mid: key numbers */}
            <div style={{ display: "flex", gap: 24, flex: 1 }}>
              <div>
                <div style={{ fontSize: 10, color: C.textDim, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.07em" }}>Original</div>
                <div style={{ fontSize: 13, fontFamily: C.mono, fontWeight: 400, color: C.text }}>${card.invoiceAmount.toLocaleString()}</div>
              </div>
              <div>
                <div style={{ fontSize: 10, color: C.textDim, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.07em" }}>Days Overdue</div>
                <div style={{ fontSize: 13, fontFamily: C.mono, fontWeight: 400, color: C.red }}>{card.daysOverdue}d</div>
              </div>
              <div>
                <div style={{ fontSize: 10, color: C.textDim, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.07em" }}>AI Floor</div>
                <div style={{ fontSize: 13, fontFamily: C.mono, fontWeight: 400, color: C.amber }}>${card.suggestedAmount.toLocaleString()}</div>
              </div>
              <div>
                <div style={{ fontSize: 10, color: C.textDim, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.07em" }}>Loss Risk</div>
                <div style={{ fontSize: 13, fontFamily: C.mono, fontWeight: 400, color: C.red }}>{card.riskOfFullLoss}</div>
              </div>
            </div>
            {/* Right: status or Review button */}
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              {card.status === "approved" && <span style={{ fontSize: 12, fontWeight: 700, color: C.green }}>✓ Approved — ${card.editAmount.toLocaleString()}</span>}
              {card.status === "dismissed" && <span style={{ fontSize: 12, fontWeight: 600, color: C.textDim }}>Dismissed</span>}
              <button onClick={() => setActiveModal(card.id)} style={{ padding: "6px 14px", fontSize: 12, fontWeight: 600, color: card.status === "pending" ? "#FFFFFF" : C.textMid, background: card.status === "pending" ? C.amber : "transparent", border: card.status === "pending" ? "none" : `1px solid ${C.border}`, borderRadius: 6, cursor: "pointer", whiteSpace: "nowrap" }} onMouseEnter={(e) => e.currentTarget.style.opacity = "0.85"} onMouseLeave={(e) => e.currentTarget.style.opacity = "1"}>
                {card.status === "pending" ? "Review" : "View"}
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Modal */}
      {activeCard && (
        <RecoveryRecModal
          card={activeCard}
          onUpdate={onUpdate}
          onClose={() => setActiveModal(null)}
        />
      )}
    </div>
  );
}

function DashboardScreen({ onSelectClient, setScreen }) {
  const [activeFilters, setActiveFilters] = useState({ status: [], dueDate: [], customer: [], invoiceNumber: [] });
  const [searchText, setSearchText] = useState("");
  const [selectedInvoiceForExchanges, setSelectedInvoiceForExchanges] = useState(null);
  const [selectedInvoiceForHistory, setSelectedInvoiceForHistory] = useState(null);
  const [recCards, setRecCards] = useState(
    negotiationRecs.map(r => ({ ...r, editAmount: r.suggestedAmount, status: "pending" }))
  );
  const [activeRecModal, setActiveRecModal] = useState(null);
  const [sortCol, setSortCol] = useState("daysOverdue");
  const [sortDir, setSortDir] = useState("desc");
  const toggleSort = (col) => { if (sortCol === col) setSortDir(d => d === "asc" ? "desc" : "asc"); else { setSortCol(col); setSortDir("desc"); } };
  const updateRec = (id, patch) => setRecCards(prev => prev.map(c => c.id === id ? { ...c, ...patch } : c));
  const activeRecCard = recCards.find(c => c.id === activeRecModal);

  const pastDueClients = clients.filter(c => c.status === "past_due" || c.status === "due");
  const totalOutstanding = pastDueClients.reduce((sum, c) => sum + c.balance, 0);
  const totalPastDue = pastDueClients.reduce((sum, c) => { const inv = clientInvoices[c.id]; return sum + (inv?.outstanding.reduce((s, i) => s + i.amount, 0) || 0); }, 0);
  const activeInvoices = pastDueClients.reduce((sum, c) => { const inv = clientInvoices[c.id]; return sum + (inv?.outstanding.length || 0); }, 0);

  const filterInvoices = (invoices) => {
    if (!invoices) return [];
    let all = [...(invoices.outstanding || []), ...(invoices.upcoming || [])];
    if (searchText.length >= 3) { const s = searchText.toLowerCase(); all = all.filter(inv => inv.clientName?.toLowerCase().includes(s) || inv.id.toLowerCase().includes(s)); }
    if (activeFilters.status.length > 0) all = all.filter(inv => activeFilters.status.includes(inv.status));
    if (activeFilters.dueDate.length > 0) all = all.filter(inv => activeFilters.dueDate.some(f => { if (f === "overdue") return inv.status === "past_due"; if (f === "due_soon") return inv.daysUntilDue && inv.daysUntilDue <= 7; if (f === "due_later") return inv.daysUntilDue && inv.daysUntilDue > 7; return false; }));
    if (activeFilters.customer.length > 0) all = all.filter(inv => activeFilters.customer.includes(inv.clientName));
    if (activeFilters.invoiceNumber.length > 0) all = all.filter(inv => activeFilters.invoiceNumber.includes(inv.id));
    return all;
  };

  return (
    <div style={{ padding: "28px 36px", minHeight: 520, fontFamily: C.sans }}>
      <style>{`button:focus-visible,a:focus-visible{outline:2px solid #2B6CB0;outline-offset:2px}`}</style>

      <div style={{ marginBottom: 24 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
          <div style={{ fontSize: 12, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.12em", marginBottom: 4 }}>Clyintel</div>
          <div style={{ fontSize: 28, lineHeight: 1.15, fontWeight: 600, color: C.navy }}>Recovery Dashboard</div>
          <div style={{ display: "flex", gap: 12 }}>
            <button onClick={() => setScreen("connections")} style={{ padding: "8px 4px", fontSize: 14, fontWeight: 500, color: C.blue, background: "transparent", border: "none", cursor: "pointer", textDecoration: "underline", textUnderlineOffset: 3 }} onMouseEnter={(e) => e.currentTarget.style.color = C.amber} onMouseLeave={(e) => e.currentTarget.style.color = C.blue}>+ Add Client</button>
          </div>
        </div>
      </div>

      {/* KPI Cards */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 16, marginBottom: 24 }}>
        {[
          { label: "Recovery YTD", value: "$42,150", color: C.green },
          { label: "Total Outstanding", value: `$${totalOutstanding.toLocaleString()}`, color: C.text },
          { label: "Past Due", value: `$${totalPastDue.toLocaleString()}`, color: C.red },
          { label: "Active Invoices", value: String(activeInvoices), color: C.text },
        ].map((kpi, i) => (
          <div key={i} style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 10, padding: 12, textAlign: "center", boxShadow: "0 2px 8px rgba(43,108,176,0.10)" }}>
            <div style={{ fontSize: 13, color: C.navy, marginBottom: 8, fontWeight: 600 }}>{kpi.label}</div>
            <div style={{ fontSize: 34, fontWeight: 700, color: kpi.color, fontFamily: C.mono }}>{kpi.value}</div>
          </div>
        ))}
      </div>

      {/* AI Negotiation Actions */}
      <NegotiationActions cards={recCards} onUpdate={updateRec} activeModal={activeRecModal} setActiveModal={setActiveRecModal} />

      {/* Filters + Search */}
      <div style={{ marginBottom: 20, display: "flex", gap: 12, alignItems: "center" }}>
        <div style={{ position: "relative" }}>
          <button onClick={() => { const d = document.getElementById("filter-dd"); d.style.display = d.style.display === "block" ? "none" : "block"; }} style={{ padding: "8px 12px", fontSize: 13, fontWeight: 500, border: `1px solid ${C.blue}`, borderRadius: 6, color: C.blue, background: C.card, cursor: "pointer", display: "flex", alignItems: "center", gap: 6 }}>
            <span>Filters</span>
            {(() => { const t = Object.values(activeFilters).reduce((s, a) => s + a.length, 0); return t > 0 ? <span style={{ background: C.blue, color: "white", borderRadius: 10, padding: "2px 6px", fontSize: 11, fontWeight: 600 }}>{t}</span> : null; })()}
            <span style={{ fontSize: 10, color: C.blue }}>▼</span>
          </button>
          <div id="filter-dd" style={{ display: "none", position: "absolute", top: "100%", left: 0, marginTop: 4, background: C.card, border: `1px solid ${C.border}`, borderRadius: 8, boxShadow: "0 4px 12px rgba(0,0,0,0.1)", zIndex: 1000, minWidth: 280, maxHeight: 400, overflow: "auto" }}>
            <div style={{ padding: "12px 16px", borderBottom: `1px solid ${C.border}` }}>
              <div style={{ fontSize: 12, fontWeight: 600, color: C.textMid, marginBottom: 8 }}>Status</div>
              {[{ v: "past_due", l: "Past Due" }, { v: "current", l: "Current" }, { v: "promise_to_pay", l: "Promise to Pay" }].map(s => (
                <label key={s.v} style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 0", cursor: "pointer" }}>
                  <input type="checkbox" checked={activeFilters.status.includes(s.v)} onChange={(e) => setActiveFilters({ ...activeFilters, status: e.target.checked ? [...activeFilters.status, s.v] : activeFilters.status.filter(x => x !== s.v) })} />
                  <span style={{ fontSize: 13, color: C.text }}>{s.l}</span>
                </label>
              ))}
            </div>
            <div style={{ padding: "12px 16px" }}>
              <div style={{ fontSize: 12, fontWeight: 600, color: C.textMid, marginBottom: 8 }}>Due Date</div>
              {[{ v: "overdue", l: "Overdue" }, { v: "due_soon", l: "Due Soon (≤7 days)" }, { v: "due_later", l: "Due Later (>7 days)" }].map(d => (
                <label key={d.v} style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 0", cursor: "pointer" }}>
                  <input type="checkbox" checked={activeFilters.dueDate.includes(d.v)} onChange={(e) => setActiveFilters({ ...activeFilters, dueDate: e.target.checked ? [...activeFilters.dueDate, d.v] : activeFilters.dueDate.filter(x => x !== d.v) })} />
                  <span style={{ fontSize: 13, color: C.text }}>{d.l}</span>
                </label>
              ))}
            </div>
          </div>
        </div>
        <div style={{ flex: 1, maxWidth: 400 }}>
          <input type="text" placeholder="Search by client or invoice number (min. 3 chars)" value={searchText} onChange={(e) => setSearchText(e.target.value)} style={{ width: "100%", padding: "8px 12px", fontSize: 13, border: `1px solid ${C.blue}`, borderRadius: 6, color: C.text, background: C.card, outline: "none" }} />
          {searchText.length > 0 && searchText.length < 3 && <div style={{ fontSize: 11, color: C.textMid, marginTop: 4 }}>Type {3 - searchText.length} more character{3 - searchText.length > 1 ? "s" : ""} to search</div>}
        </div>
      </div>

      {/* Invoice Table */}
      <div style={{ border: `1px solid ${C.border}`, borderRadius: 10, overflow: "hidden" }}>
        {(() => {
          const SortBtn = ({ col, label }) => {
            const active = sortCol === col;
            const arrow = active ? (sortDir === "asc" ? " ↑" : " ↓") : " ↕";
            return (
              <button onClick={() => toggleSort(col)} style={{ background: "none", border: "none", cursor: "pointer", padding: 0, fontSize: 12, fontWeight: 600, color: C.navy, textTransform: "uppercase", letterSpacing: "0.05em", display: "flex", alignItems: "center", gap: 3, whiteSpace: "nowrap" }}>
                {label}<span style={{ fontSize: 14, color: C.blue, opacity: active ? 1 : 0.4 }}>{arrow}</span>
              </button>
            );
          };
          return (
            <div style={{ display: "grid", gridTemplateColumns: "160px 120px 120px 120px 100px 120px 1fr 36px", alignItems: "center", padding: "12px 16px", paddingRight: 24, gap: 14, background: C.surface, borderBottom: `1px solid ${C.border}` }}>
              <SortBtn col="clientName" label="Client" />
              <SortBtn col="id" label="Invoice #" />
              <SortBtn col="amount" label="Amount" />
              <SortBtn col="dueDate" label="Due Date" />
              <SortBtn col="daysOverdue" label="Due In" />
              <SortBtn col="status" label="Status" />
              <SortBtn col="lastActivity" label="Last Activity" />
              <div />
            </div>
          );
        })()}

        {(() => {
          const sortFn = (a, b) => {
            let av, bv;
            if (sortCol === "amount") { av = a.amount || 0; bv = b.amount || 0; }
            else if (sortCol === "daysOverdue") {
              // Unified signed value: past due = negative, upcoming = positive
              av = a.status === "past_due" ? -(a.daysOverdue || 0) : (a.daysUntilDue || 0);
              bv = b.status === "past_due" ? -(b.daysOverdue || 0) : (b.daysUntilDue || 0);
            }
            else if (sortCol === "dueDate") { av = new Date(a.dueDate || 0); bv = new Date(b.dueDate || 0); }
            else { av = (a[sortCol] || "").toString().toLowerCase(); bv = (b[sortCol] || "").toString().toLowerCase(); }
            if (av < bv) return sortDir === "asc" ? -1 : 1;
            if (av > bv) return sortDir === "asc" ? 1 : -1;
            return 0;
          };

          const allInvoices = pastDueClients.flatMap(client => {
            const invoices = clientInvoices[client.id];
            return filterInvoices(invoices).map(inv => ({ ...inv, clientName: client.name, clientId: client.id }));
          }).sort(sortFn);

          return allInvoices.map((inv, idx) => {
            const statusMap = { current: { label: "Current", color: C.text }, due: { label: "Due", color: C.amber }, past_due: { label: "Past due", color: C.red }, recovered: { label: "Recovered", color: C.blue } };
            const statusStyle = statusMap[inv.status] || { label: inv.status, color: C.text };
            const prevSameClient = idx > 0 && allInvoices[idx - 1].clientId === inv.clientId;
            const isLastRow = idx === allInvoices.length - 1;
            const rec = recCards.find(c => c.id === inv.id);

            return (
              <div key={inv.id} style={{ display: "grid", gridTemplateColumns: "160px 120px 120px 120px 100px 120px 1fr 36px", alignItems: "center", padding: "18px 16px", paddingRight: 24, borderBottom: isLastRow ? "none" : `1px solid ${C.border}`, fontSize: 14, gap: 14, background: selectedInvoiceForHistory === inv.id ? C.blueBg : "#FFFFFF", borderLeft: selectedInvoiceForHistory === inv.id ? `3px solid ${C.blue}` : "3px solid transparent" }}>
                <div>
                  <button onClick={() => { const client = clients.find(c => c.id === inv.clientId); if (client) onSelectClient(client); }} style={{ fontWeight: prevSameClient ? 400 : 600, fontSize: prevSameClient ? 13 : 14, color: C.blue, background: "transparent", border: "none", cursor: "pointer", padding: 0, paddingLeft: prevSameClient ? 10 : 0, textAlign: "left" }} onMouseEnter={(e) => e.currentTarget.style.color = C.amber} onMouseLeave={(e) => e.currentTarget.style.color = C.blue}>{inv.clientName}</button>
                </div>
                <div>
                  <button onClick={() => setSelectedInvoiceForHistory(inv.id)} style={{ fontFamily: C.mono, color: C.blue, fontSize: 14, background: "transparent", border: "none", cursor: "pointer", padding: 0 }} onMouseEnter={(e) => e.currentTarget.style.color = C.amber} onMouseLeave={(e) => e.currentTarget.style.color = C.blue}>{inv.id}</button>
                </div>
                <div style={{ fontFamily: C.mono, fontSize: 15, color: inv.status === "past_due" ? C.red : C.text }}>${inv.amount.toLocaleString()}</div>
                <div style={{ color: inv.status === "past_due" ? C.red : C.textMid }}>{inv.dueDate}</div>
                <div style={{ fontWeight: 500, color: inv.status === "past_due" ? C.red : C.text }}>{inv.status === "past_due" && inv.daysOverdue ? `-${inv.daysOverdue}d` : inv.daysUntilDue ? `${inv.daysUntilDue}d` : "—"}</div>
                <div style={{ fontSize: 13, color: statusStyle.color }}>{statusStyle.label}</div>
                <div style={{ fontSize: 13, color: C.textMid, lineHeight: 1.4 }}>
                  {(() => {
                    const exchanges = invoiceExchanges[inv.id];
                    if (!exchanges || exchanges.length === 0) return "—";
                    const last = exchanges[exchanges.length - 1];
                    const icons = { "Voice": "📞", "Email": "📧", "Text": "💬" };
                    const date = last.timestamp.split(" ")[0];
                    const outcome = last.outcome.length > 50 ? last.outcome.substring(0, 50) + "..." : last.outcome;
                    return <div style={{ display: "flex", flexDirection: "column", gap: 2 }}><div style={{ display: "flex", gap: 8 }}><span style={{ fontWeight: 600, color: C.text }}>{date}</span><span style={{ color: C.textMid }}>{icons[last.channel]} {last.channel}</span></div><div style={{ fontStyle: "italic", fontSize: 12 }}>{outcome}</div></div>;
                  })()}
                </div>
                <div style={{ display: "flex", alignItems: "center", justifyContent: "center" }}>
                  {rec && (
                    <button onClick={() => setActiveRecModal(rec.id)} title={rec.status === "approved" ? "Approved recovery rec" : rec.status === "dismissed" ? "Dismissed recovery rec" : "Recovery recommendation pending"} style={{ width: 26, height: 26, borderRadius: "50%", border: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 13, background: rec.status === "approved" ? C.greenBg : rec.status === "dismissed" ? C.surface : C.amberBg, color: rec.status === "approved" ? C.green : rec.status === "dismissed" ? C.textDim : C.amber }} onMouseEnter={(e) => e.currentTarget.style.opacity = "0.75"} onMouseLeave={(e) => e.currentTarget.style.opacity = "1"}>
                      {rec.status === "approved" ? "✓" : rec.status === "dismissed" ? "○" : "!"}
                    </button>
                  )}
                </div>
              </div>
            );
          });
        })()}
      </div>

      {selectedInvoiceForHistory && (
        <ExchangeDrawer invoiceId={selectedInvoiceForHistory} onClose={() => setSelectedInvoiceForHistory(null)} />
      )}
      {activeRecCard && (
        <RecoveryRecModal card={activeRecCard} onUpdate={updateRec} onClose={() => setActiveRecModal(null)} />
      )}
    </div>
  );
}

function DetailScreen({ client, setScreen, previousScreen = "dashboard" }) {
  const [selectedInvoiceForExchanges, setSelectedInvoiceForExchanges] = useState(null);
  const scoreColor = client.score >= 80 ? C.green : client.score >= 60 ? C.amber : C.red;
  const scoreLabel = client.score >= 80 ? "Low risk" : client.score >= 60 ? "Medium risk" : "High risk";
  const backLabel = previousScreen === "client-list" ? "Back to Portfolio" : "Back to Recovery";

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 0, padding: "28px 36px", minHeight: 520, fontFamily: C.sans }}>
      <style>{`@keyframes fadeUp{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}button:focus-visible{outline:2px solid #2B6CB0;outline-offset:2px}`}</style>

      <div style={{ marginBottom: 24 }}>
        <button onClick={() => setScreen(previousScreen)} style={{ display: "flex", alignItems: "center", gap: 6, padding: "8px 12px", fontSize: 14, fontWeight: 600, color: C.blue, background: "transparent", border: "none", cursor: "pointer", marginBottom: 12 }} onMouseEnter={(e) => e.currentTarget.style.textDecoration = "underline"} onMouseLeave={(e) => e.currentTarget.style.textDecoration = "none"}>
          <span style={{ fontSize: 16 }}>←</span> {backLabel}
        </button>
        <div style={{ fontSize: 12, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.12em", marginBottom: 4 }}>Clyintel</div>
        <div style={{ fontSize: 28, fontWeight: 600, color: C.navy }}>Clyintel Analyzer</div>
      </div>

      <div style={{ display: "flex", gap: 24, alignItems: "flex-start" }}>
        {/* Left Panel */}
        <div style={{ flex: 1 }}>
          {/* Client header — derived from actual invoice data */}
          {(() => {
            const invoices = clientInvoices[client.id];
            const outstanding = [...(invoices?.outstanding || []), ...(invoices?.upcoming || [])];
            const overdueInvoices = outstanding.filter(i => i.status === "past_due");
            const maxDaysOverdue = overdueInvoices.length > 0 ? Math.max(...overdueInvoices.map(i => i.daysOverdue || 0)) : 0;
            return (
              <div style={{ marginBottom: 20 }}>
                <div style={{ fontSize: 22, fontWeight: 600, color: C.text }}>{client.name}</div>
              </div>
            );
          })()}

          {/* PTR */}
          {(() => {
            const isLowRisk = client.score >= 80;
            const accentColor = isLowRisk ? C.green : C.amber;
            const accentBg = isLowRisk ? C.greenBg : C.amberBg;
            const terms = isLowRisk ? "Net 30 with standard terms" : "Net 15 with 2% early payment discount";
            const reminder = isLowRisk ? "-7, -3, 0 days" : "-14, -7, -3, 0 days";
            const reminderLabel = isLowRisk ? "3-touch sequence" : "4-touch escalation";
            const whyText = isLowRisk
              ? "Strong payment history supports standard terms. Low risk profile enables a flexible payment schedule without increasing exposure. The 3-touch reminder sequence maintains top-of-mind awareness without being intrusive."
              : "Shorter terms reduce your exposure window. The 2% early payment incentive directly addresses cash flow constraints that drive late payments. The 4-touch escalation sequence increases urgency progressively to maximize on-time collection.";
            const lossReduction = isLowRisk ? "12%" : "38%";
            const revenueImpact = isLowRisk ? "$525" : "$3,224";
            // Revenue at Risk = balance × estimated loss probability
            const lossPct = isLowRisk ? 0.05 : 0.42;
            const revenueAtRisk = Math.round(client.balance * lossPct);

            return (
              <div style={{ border: `1px solid ${C.border}`, borderRadius: 10, overflow: "hidden", marginBottom: 16 }}>
                {/* Header — no background, no bottom divider */}
                <div style={{ padding: "14px 20px" }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.12em", marginBottom: 10 }}>Payment Terms Recommendation</div>
                  <div style={{ display: "flex", alignItems: "flex-start", gap: 24 }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 11, fontWeight: 600, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 4 }}>Terms</div>
                      <div style={{ fontSize: 15, fontWeight: 700, color: C.text }}>{terms}</div>
                    </div>
                    <div style={{ width: 1, background: C.border, alignSelf: "stretch" }} />
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 11, fontWeight: 600, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 4 }}>Reminder Strategy</div>
                      <div style={{ fontSize: 15, fontWeight: 700, color: C.blue }}>{reminder}</div>
                      <div style={{ fontSize: 11, color: C.textDim, marginTop: 2 }}>{reminderLabel}</div>
                    </div>
                  </div>
                </div>

                {/* Why This Matters */}
                <div style={{ padding: "0 20px 14px" }}>
                  <div style={{ background: accentBg, border: `1px solid ${accentColor}22`, borderRadius: 8, padding: "12px 14px" }}>
                    <div style={{ fontSize: 11, fontWeight: 700, color: accentColor, letterSpacing: "0.08em", textTransform: "uppercase", marginBottom: 6 }}>Why this matters</div>
                    <div style={{ fontSize: 14, fontWeight: 500, color: C.text, lineHeight: 1.7 }}>{whyText}</div>
                  </div>
                </div>

                {/* Projections */}
                <div style={{ padding: "0 20px 20px" }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: 12 }}>Projections</div>
                  <div style={{ display: "flex", gap: 0 }}>
                    {/* Decrease Loss By */}
                    <div style={{ flex: 1, textAlign: "center" }}>
                      <div style={{ fontSize: 11, color: C.textMid, fontWeight: 600, marginBottom: 8 }}>Decrease Loss By</div>
                      <div style={{ fontSize: 32, fontWeight: 700, color: C.green, fontFamily: C.mono, lineHeight: 1 }}>{lossReduction}</div>
                      <div style={{ fontSize: 11, color: C.textDim, marginTop: 6 }}>vs. current terms</div>
                    </div>
                    {/* Vertical divider */}
                    <div style={{ width: 1, background: C.border, margin: "0 4px" }} />
                    {/* Revenue Impact */}
                    <div style={{ flex: 1, textAlign: "center" }}>
                      <div style={{ fontSize: 11, color: C.textMid, fontWeight: 600, marginBottom: 8 }}>Revenue Impact</div>
                      <div style={{ fontSize: 32, fontWeight: 700, color: isLowRisk ? C.green : C.red, fontFamily: C.mono, lineHeight: 1 }}>{revenueImpact}</div>
                      <div style={{ fontSize: 11, color: C.textDim, marginTop: 6 }}>est. annual delay cost</div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })()}

          {/* Divider */}
          <div style={{ borderTop: `1px solid ${C.border}`, margin: "4px 0 16px" }} />

          {/* Invoice Summary — single widget */}
          {(() => {
            const invoices = clientInvoices[client.id];
            if (!invoices) return null;
            const allInvoices = [...(invoices.outstanding || []), ...(invoices.upcoming || [])];
            const totalPastDue = allInvoices.filter(i => i.status === "past_due").reduce((s, i) => s + i.amount, 0);
            const recoveredCount = client.invoices - allInvoices.length;
            const totalRecovered = (invoices.paid || []).reduce((s, i) => s + i.amount, 0);
            const stats = [
              { label: "Total Outstanding", value: `$${allInvoices.reduce((s, i) => s + i.amount, 0).toLocaleString()}`, color: C.text },
              { label: "Total Past Due", value: totalPastDue > 0 ? `$${totalPastDue.toLocaleString()}` : "—", color: totalPastDue > 0 ? C.red : C.textDim },
              { label: "Total Recovered", value: totalRecovered > 0 ? `$${totalRecovered.toLocaleString()}` : "—", color: totalRecovered > 0 ? C.green : C.textDim },
            ];
            return (
              <div style={{ border: `1px solid ${C.border}`, borderRadius: 10, overflow: "hidden", marginBottom: 12 }}>
                <div style={{ padding: "10px 16px", background: C.surface, borderBottom: `1px solid ${C.border}` }}>
                  <span style={{ fontSize: 11, fontWeight: 600, color: C.navy, textTransform: "uppercase", letterSpacing: "0.06em" }}>Invoice Summary</span>
                </div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)" }}>
                  {stats.map((w, i, arr) => (
                    <div key={w.label} style={{ padding: "14px 16px", borderRight: i < arr.length - 1 ? `1px solid ${C.border}` : "none", textAlign: "center" }}>
                      <div style={{ fontSize: 11, color: C.navy, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.07em", marginBottom: 6 }}>{w.label}</div>
                      <div style={{ fontSize: 20, fontWeight: 700, color: w.color, fontFamily: C.mono }}>{w.value}</div>
                    </div>
                  ))}
                </div>
              </div>
            );
          })()}

          {/* Invoice History Table */}
          <div style={{ border: `1px solid ${C.border}`, borderRadius: 10, overflow: "hidden" }}>
            <div style={{ padding: "10px 16px", background: C.surface, borderBottom: `1px solid ${C.border}` }}>
              <span style={{ fontSize: 11, fontWeight: 600, color: C.navy, textTransform: "uppercase", letterSpacing: "0.06em" }}>Invoice History</span>
            </div>
            {(() => {
              const invoices = clientInvoices[client.id];
              if (!invoices) return null;
              const allInvoices = [
                ...(invoices.outstanding || []),
                ...(invoices.upcoming || []),
                ...(invoices.paid || []),
              ];
              if (allInvoices.length === 0) return <div style={{ textAlign: "center", padding: "40px 20px", color: "#6B7280" }}>No invoices found for this client.</div>;
              return (
                <>
                  <div style={{ display: "grid", gridTemplateColumns: "120px 120px 120px 100px 120px 1fr", gap: 16, padding: "12px 16px", background: C.surface, borderBottom: `1px solid ${C.border}`, fontSize: 11, fontWeight: 600, color: C.navy, textTransform: "uppercase", letterSpacing: "0.06em" }}>
                    <div>Invoice #</div><div>Amount</div><div>Due Date</div><div>Due In</div><div>Status</div><div>Last Activity</div>
                  </div>
                  {allInvoices.map((inv, i) => {
                    const isPastDue = inv.status === "past_due";
                    const isPaid = inv.status === "paid";
                    const dueInValue = isPaid ? (inv.paidDate || "—") : isPastDue && inv.daysOverdue ? `-${inv.daysOverdue}d` : inv.daysUntilDue ? `${inv.daysUntilDue}d` : "—";
                    const statusColor = isPaid ? C.green : isPastDue ? C.red : C.text;
                    const statusLabel = isPaid ? "Paid" : isPastDue ? "Past Due" : "Current";
                    const dueInLabel = isPaid ? "Paid" : "Due In";
                    return (
                      <div key={inv.id} style={{ display: "grid", gridTemplateColumns: "120px 120px 120px 100px 120px 1fr", gap: 16, padding: "14px 16px", borderBottom: i < allInvoices.length - 1 ? `1px solid ${C.border}` : "none", fontSize: 14, alignItems: "center", background: isPaid ? "rgba(22,163,74,0.03)" : "transparent" }}>
                        <div onClick={() => !isPaid && setSelectedInvoiceForExchanges(inv.id)} style={{ fontFamily: C.mono, fontSize: 13, color: isPaid ? C.textMid : C.blue, cursor: isPaid ? "default" : "pointer" }} onMouseEnter={(e) => { if (!isPaid) e.currentTarget.style.color = C.amber; }} onMouseLeave={(e) => { if (!isPaid) e.currentTarget.style.color = C.blue; }}>{inv.id}</div>
                        <div style={{ fontFamily: C.mono, fontSize: 15, color: isPastDue ? C.red : C.text }}>${inv.amount.toLocaleString()}</div>
                        <div style={{ fontSize: 14, color: isPastDue ? C.red : C.textMid }}>{inv.dueDate}</div>
                        <div style={{ fontSize: 13, color: isPaid ? C.green : isPastDue ? C.red : C.text }}>{dueInValue}</div>
                        <div style={{ fontSize: 13, fontWeight: isPaid ? 600 : 400, color: statusColor }}>{statusLabel}</div>
                        <div style={{ fontSize: 13, color: C.textMid }}>{inv.lastActivity}</div>
                      </div>
                    );
                  })}
                </>
              );
            })()}
          </div>
        </div>

        {/* Right Rail - Client Score */}
        <div style={{ width: 300 }}>
          <div style={{ border: `1px solid ${C.border}`, borderRadius: 10, padding: "18px 20px", position: "sticky", top: 20 }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.12em", marginBottom: 12 }}>Client Score</div>
            <div style={{ marginBottom: 16 }}>
              <div style={{ display: "flex", alignItems: "baseline", gap: 8, marginBottom: 6 }}>
                <div style={{ fontSize: 48, fontWeight: 700, color: scoreColor, fontFamily: C.mono }}>{client.score}</div>
                <div style={{ fontSize: 14, color: C.textMid }}>
                  {(() => { const prev = client.score >= 80 ? 82 : 52; const change = client.score - prev; return <span style={{ color: scoreColor, fontWeight: 600 }}>{change > 0 ? "▲" : "▼"} {Math.abs(change)}</span>; })()} (prev: {client.score >= 80 ? 82 : 52})
                </div>
              </div>
              <div style={{ fontSize: 12, color: C.textMid, marginBottom: 10 }}>out of 100</div>
              <div style={{ height: 6, borderRadius: 3, background: "linear-gradient(to right, #DC2626 0%, #F59E0B 50%, #16A34A 100%)", marginBottom: 12, position: "relative" }}>
                <div style={{ position: "absolute", left: `${client.score}%`, top: -2, width: 10, height: 10, borderRadius: "50%", background: scoreColor, border: "2px solid #FFFFFF" }} />
              </div>
              <div style={{ fontSize: 15, fontWeight: 700, color: scoreColor, marginBottom: 14 }}>{scoreLabel}</div>
            </div>
            <div style={{ marginBottom: 16 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.12em", marginBottom: 10 }}>Score Summary</div>
              <div style={{ paddingLeft: 8 }}>
                <div style={{ fontSize: 14, fontWeight: 500, color: C.textMid, marginBottom: 6 }}>• Frequent delays</div>
                <div style={{ fontSize: 14, fontWeight: 500, color: C.textMid }}>• Below average payer</div>
              </div>
            </div>
            <div style={{ marginBottom: 16 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.12em", marginBottom: 10 }}>Score Factors</div>
              <div style={{ paddingLeft: 8 }}>
                <div style={{ fontSize: 14, fontWeight: 500, color: C.textMid, marginBottom: 6 }}>• 6 of 8 invoices paid late</div>
                <div style={{ fontSize: 14, fontWeight: 500, color: C.textMid }}>• Avg delay: 26 days</div>
              </div>
            </div>
            <div style={{ borderTop: `1px solid ${C.border}`, margin: "16px 0" }} />
            <div>
              <div style={{ fontSize: 11, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: "0.12em", marginBottom: 10 }}>Risk Drivers</div>
              <div style={{ paddingLeft: 8 }}>
                <div style={{ fontSize: 14, fontWeight: 500, color: C.textMid, marginBottom: 6 }}>• Lump-sum billing is the primary risk driver</div>
                <div style={{ fontSize: 14, fontWeight: 500, color: C.textMid }}>• No late fee penalties applied to past due payments</div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {selectedInvoiceForExchanges && (
        <ExchangeDrawer invoiceId={selectedInvoiceForExchanges} onClose={() => setSelectedInvoiceForExchanges(null)} />
      )}
    </div>
  );
}

export default function ClyintelAfter() {
  const [screen, setScreen] = useState("dashboard");
  const [selectedClient, setSelectedClient] = useState(null);
  const [previousScreen, setPreviousScreen] = useState("dashboard");
  const lastUpdated = "4/20/26 9:41 AM";

  const handleSelectClient = (client) => {
    setPreviousScreen(screen);
    setSelectedClient(client);
    setScreen("detail");
  };

  const footerText = screen === "connections" ? "Connect a service to get started"
    : screen === "client-list" ? "View and manage all clients"
    : screen === "dashboard" ? "Select a client to view collection history and scoring"
    : "Collection history — " + (selectedClient?.name || "");

  return (
    <div style={{ fontFamily: C.sans, background: C.bg, minHeight: "100vh", display: "flex", flexDirection: "column" }}>
      <link rel="stylesheet" href={FONT_URL} />

      {/* Header */}
      <div style={{ background: "#FFFFFF", borderBottom: `1px solid ${C.border}`, padding: "0 24px", display: "flex", alignItems: "center", height: 52, flexShrink: 0 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginRight: 24 }}>
          <img src="data:image/png;base64," style={{ height: 56, objectFit: "contain" }} alt="Phoresight" />
        </div>
        <div style={{ flex: 1 }} />
        <div style={{ display: "flex", gap: 4 }}>
          {[
            { label: "Recovery", action: () => setScreen("dashboard"), active: screen === "dashboard" || screen === "detail" && previousScreen === "dashboard", greyed: false },
            { label: "Portfolio", action: () => setScreen("client-list"), active: screen === "client-list" || screen === "detail" && previousScreen === "client-list", greyed: false },
            { label: "Settings", action: null, active: false, greyed: true },
          ].map(item => (
            <button key={item.label} onClick={item.action || undefined} style={{ padding: "6px 14px", fontSize: 13, fontWeight: item.active ? 600 : 400, color: item.active ? C.blue : C.textDim, background: "transparent", border: "none", cursor: item.greyed ? "not-allowed" : "pointer", opacity: item.greyed ? 0.5 : 1 }}>
              {item.label}
            </button>
          ))}
        </div>
        <div style={{ width: 32, height: 32, borderRadius: "50%", background: C.navy, display: "flex", alignItems: "center", justifyContent: "center", marginLeft: 16 }}>
          <span style={{ fontSize: 13, fontWeight: 600, color: "#FFFFFF" }}>JD</span>
        </div>
      </div>

      {/* Main Content */}
      <div style={{ flex: 1, overflowY: "auto" }}>
        {screen === "connections" && <ConnectionsScreen setScreen={setScreen} />}
        {screen === "dashboard" && <DashboardScreen onSelectClient={handleSelectClient} setScreen={setScreen} />}
        {screen === "client-list" && <ClientListScreen setScreen={setScreen} onSelectClient={handleSelectClient} />}
        {screen === "detail" && selectedClient && <DetailScreen client={selectedClient} setScreen={setScreen} previousScreen={previousScreen} />}
      </div>

      {/* Footer */}
      <div style={{ background: C.surface, borderTop: `1px solid ${C.border}`, padding: "9px 24px", display: "flex", justifyContent: "space-between", alignItems: "center", flexShrink: 0 }}>
        <span style={{ fontSize: 11, color: C.textDim, fontFamily: C.mono }}>{footerText}</span>
        <span style={{ fontSize: 11, color: C.textDim }}>Updated {lastUpdated}</span>
      </div>

    </div>
  );
}
